"""
mkt-original | Leviticus | 1-4
Script: zc-original-leviticus-1-4-fill.py
Run: python3 scripts/zc-original-leviticus-1-4-fill.py

Ch 1: The 'olah (burnt offering) — ascending sacrifice fully consumed on the altar
Ch 2: The minchah (grain offering) — non-animal tribute; azkara, salt covenant, firstfruits
Ch 3: The zevach shelamim (fellowship/peace offering) — from shalom; chelev and blood reserved for YHWH
Ch 4: The chattat (purification/sin offering) for unintentional sin (bishgagah) — gradated by social rank

Key Hebrew terms:
- qorban (H7133): from qarav = to draw near; offering as act of approach not appeasement
- 'olah (H5930): from alah = to go up; entirely ascending/consumed
- minchah (H4503): grain tribute; 'azkara = memorial portion burned as representative
- shelamim (H8002): from shalom or shalem (to complete/repay); the communal meal offering
- chattat (H2403): purification offering; covers unintentional (bishgagah) violations only
- kipper (H3722): to cover or to ransom; the act of atonement — root of Yom Kippur
- reah nihoah (H7381+H5207): soothing aroma; the sacrifice as what pacifies divine response
- chelev (H2459): the best fat; reserved for YHWH; eating it forbidden by chuqat 'olam
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

LEVITICUS = {
    "1": {
        "1": "<p><strong>Vayiqra el-Moshe</strong> (<em>vayiqra</em>): 'And he called to Moses.' The book's Hebrew title is <em>Vayiqra</em> from this opening word (Greek <em>Leuitikon</em> = 'Levitical things'). The divine calling from the tent of meeting (<em>ohel mo'ed</em>) is not a new revelation but a continuation of Sinai: YHWH now speaks from within the tabernacle just completed. The shift from Sinai's mountain to the tent marks the portability of the covenant — the holy space moves with the people.</p>",
        "2": "<p><strong>adam ki yaqriv mikem qorban la-YHWH</strong> (<em>qorban</em>, H7133): 'When any person among you brings a <em>qorban</em> to YHWH.' The word <em>qorban</em> derives from <em>qarav</em> (to draw near, to approach) — an offering is fundamentally an act of approach, not appeasement. <em>Adam</em> (a person — the generic human term, from <em>adamah</em> = ground) signals the universal scope: any person, not just a priest or official, may bring an offering. The democratization of access to YHWH is built into the vocabulary of sacrifice.</p>",
        "3": "<p><strong>'olah</strong> (H5930): 'burnt offering.' From <em>alah</em> (to go up, to ascend): the <em>'olah</em> is the entirely ascending sacrifice — every part goes up in smoke to YHWH, nothing returned to the offerer. <strong>Tamim</strong> (H8549): 'without defect, blameless' — the same term used of Noah (Gen 6:9 'Noah was <em>tamim</em>') and Abraham (Gen 17:1 'walk before me and be <em>tamim</em>'). <strong>Ratzon</strong> (H7522): acceptance, favor, goodwill — the sacrifice is presented 'so that it may be accepted for him' (<em>lirtsono</em>). The <em>'olah</em> is the offering of total dedication: the whole self, symbolized by the whole animal, going up to God.</p>",
        "5": "<p><strong>shachat</strong> (H7819) 'to slaughter' + <strong>zaraq</strong> (H2236) 'to sprinkle/toss': the two key sacrificial actions distinct from one another — killing and blood-application are separate ritual acts performed by separate parties (the offerer kills; the priests handle the blood). <strong>Dam</strong> (H1818) 'blood': its application around the altar (<em>al ha-mizbeach saviv</em>) will be explained theologically in Lev 17:11 — 'the life (<em>nefesh</em>) of the flesh is in the blood, and I have given it to you on the altar to make atonement for your souls.'</p>",
        "6": "<p><strong>hifshit et ha-'olah venitteach otah linetachehah</strong>: 'He skins the burnt offering and cuts it into pieces.' <em>Nittach</em> (H5408): to cut into specified pieces — the animal is not burned whole but dismembered into portions. This contrasts with the bird offering (vv. 14-17) which is not cut apart. The skinning and portioning is the offerer's work; the arrangement and burning belong to the priests. The labor division reflects the collaborative nature of the sacrifice: offerer and priest each have required roles.</p>",
        "7": "<p><strong>venatan bene Aharon ha-kohen esh al ha-mizbeach</strong>: Aaron's sons arrange fire on the altar and wood upon the fire. The altar fire is divinely kindled (Lev 9:24 fire came out from before YHWH) and must never go out (Lev 6:13 '<em>esh tamid</em>' = perpetual fire). The priests' role in arranging wood ensures the fire is maintained through human stewardship of what God initiated. The combination of divine origin and human maintenance is characteristic of covenant institutions.</p>",
        "8": "<p><strong>rosh</strong> (H7218) 'head' + <strong>peder</strong> (H6309) 'the fat pieces/suet': the head and suet are arranged on the burning wood in a specific order (<em>ve'archu</em> = 'they arrange in order'). The technical precision of the ritual ordering reflects its communicative function: a properly arranged sacrifice speaks; an improperly arranged one does not. The priests as arranged-order specialists is what makes the sacrificial system communicative rather than merely transactional.</p>",
        "9": "<p><strong>qerev</strong> (H7130) 'inner parts/entrails' and <strong>karaim</strong> (H3767) 'legs': washed with water before burning. The washing of the internal organs and legs addresses the parts most visibly soiled — the contents of the gut and the dirt of travel. Even in sacrifice, ritual purity is addressed before the offering ascends. <strong>Reah nihoah</strong> (H7381+H5207): 'soothing/pleasing aroma' — a metaphorical idiom for what satisfies the divine response. The term <em>nihoah</em> derives from <em>nuach</em> (to rest, settle) — the aroma is what causes YHWH's response to settle/rest from potential judgment. Used first of Noah (Gen 8:21), where the same phrase appears after the flood.</p>",
        "10": "<p><strong>tzon</strong> (H6629): 'flock' — sheep or goats. The graded sacrificial system moves from large animals (herd, v.2) to small animals (flock, v.10) to birds (v.14), calibrated to the offerer's means. This graduated access ensures that no one is excluded from the <em>'olah</em> by economic constraint. The same animal standard applies regardless of socioeconomic class: <em>tamim zachar</em> (a blameless male) across all categories.</p>",
        "11": "<p><strong>ve'shachat oto al yerekh ha-mizbeach tzafonah</strong>: slaughter on the north side of the altar. The north-side specification for the <em>'olah</em> and later the <em>chattat</em> (Lev 4:24, 6:25) is never explicitly explained in the text. Rabbinic tradition associated the north with divine judgment (cf. Jer 1:14 'from the north disaster will be poured out'); this may encode the direction of sacrificial atonement. The spatial precision of the ritual — specific sides, specific movements — maps the tabernacle as a geography of meaning.</p>",
        "12": "<p><strong>linetiachehah</strong>: into its pieces — repeated from v.6 to confirm the cutting procedure applies to flock animals as well as cattle. The portions specified: head, fat (<em>peder</em>), and remaining pieces (<em>netachim</em>). The arrangement is identical regardless of the animal's size — the ritual form is stable even as the material scales down. Consistency of form across economic categories reinforces that the significance is in the act, not the magnitude of the gift.</p>",
        "13": "<p><strong>qerev vekaraim</strong> (inner organs and legs) again washed with water — repeated from v.9 for flock animals. The refrain of washing before burning and the formula <em>reah nihoah la-YHWH</em> marks the conclusion of each variant: the outcome is the same regardless of the animal used. The liturgical repetition is not redundancy but reinforcement: the system of access is genuinely available at all levels.</p>",
        "14": "<p><strong>'olah min ha-'of</strong> (<em>'of</em>, H5775): 'burnt offering from birds (<em>turtledove</em> or <em>young pigeon</em>).' <em>Tor</em> (H8449, turtledove) and <em>ben-yonah</em> (H1469, young pigeon) are the most economical sacrifice possible — the provision for the very poor. Lev 12:8 allows birds as an alternative to a lamb for new mothers who cannot afford a sheep; Luke 2:24 records that Mary and Joseph brought 'a pair of turtledoves or two young pigeons' — the offering of those without means, identifying Jesus with the economically poor from birth.</p>",
        "15": "<p><strong>malaph et rosho</strong> (<em>malaph</em>, H4454): 'to wring off the head' — a specific technique for bird sacrifice distinct from the knife-slaughter used for mammals. The blood is drained against the side of the altar (<em>himatzer</em>). Birds are not skinned or portioned but prepared whole. The unique method for bird sacrifice — itself a unique provision for those who cannot afford animals — shows that the system is adapted to the offerer's condition at every level, not applied uniformly regardless of context.</p>",
        "16": "<p><strong>muria</strong> (H4239): the crop/craw (digestive organ of the bird); <strong>notzato</strong> (H5133): feathers or wing-tips. These are removed and thrown by the altar at the ash heap on the east side (<em>miqom ha-deshen</em>). The bird's digestive contents (which would be unclean) are discarded before the offering ascends. The separation of the digestible interior from the ascent portion maintains the purity of what goes up to YHWH even in the least expensive offering category.</p>",
        "17": "<p><strong>shissa oto vikhnafav</strong>: 'He splits it at its wings without dividing it completely.' Unlike animal offerings, the bird is not cut apart — it is torn open at the wings and spread flat for burning. The result is a flattened, opened bird laid on the altar wood. <em>Reah nihoah la-YHWH</em> closes the chapter: regardless of whether the offering is a bull or a pigeon, the formula is the same. The theological outcome of the sacrifice — YHWH's soothing response — is not indexed to the economic value of the offering.</p>"
    },
    "2": {
        "1": "<p><strong>minchah</strong> (H4503): 'grain offering, tribute.' From a root meaning 'to give, to present' (related to the verb <em>manah</em> = to apportion). In older biblical usage <em>minchah</em> can refer to any tribute or gift (Gen 32:14 Jacob's gift to Esau; 1 Sam 10:27). By Leviticus it has specialized to the non-animal tribute offering. <strong>Solet</strong> (H5560): fine/sifted flour (as opposed to coarser <em>qemach</em>). <strong>Shemen</strong> (H8081): olive oil. <strong>Levonah</strong> (H3828): frankincense — a costly aromatic resin. The <em>minchah</em> accompanies the animal offerings as a secondary tribute; it is also appropriate as the offering of those who cannot afford animals (Lev 5:11).</p>",
        "2": "<p><strong>'azkara</strong> (H234): 'memorial portion' — from <em>zakar</em> (to remember). The priest burns a representative handful of flour, oil, and all the frankincense as the <em>'azkara</em> — the portion that makes the whole offering 'remembered' (<em>zakar</em>) before YHWH. The Latin term is <em>pars pro toto</em> — a part that represents the whole. The theological claim is that the burning of a portion has the full effect of burning the whole: the representational logic underlying the entire sacrificial system (and by extension all atonement by substitution).</p>",
        "3": "<p><strong>qodesh qodashim</strong> (H6944 doubled): 'most holy' — the superlative formed by doubling the noun. The remainder of the <em>minchah</em> after the <em>'azkara</em> is burned belongs to Aaron and his sons. The classification <em>qodesh qodashim</em> signals that priestly portions carry the highest degree of holiness — they must be eaten within the sanctuary by male priests only. The graduated holiness system (most holy / holy / clean / unclean) is the spatial-moral architecture of Leviticus.</p>",
        "4": "<p><strong>challot matza</strong> and <strong>raqiqim</strong>: 'unleavened loaves' and 'unleavened wafers.' The <em>minchah</em> baked in an oven must be unleavened. <em>Matza</em> (H4682, unleavened bread) is a requirement for all grain offerings offered as <em>isheh</em> (fire offering to YHWH) — Lev 2:11 will explain that leaven cannot be offered. The unleavened requirement for any grain offering brought into the altar's fire reinforces that the fire-offering category is set apart from everyday baked goods.</p>",
        "5": "<p><strong>al ha-machavat</strong> (<em>machavat</em>, H4227): 'on the flat griddle/pan.' A shallow, flat griddle produces a thin, unleavened cake. Three cooking methods are specified (oven, griddle, deep pan) because the <em>minchah</em> can be prepared at different domestic facilities. The flexibility of preparation method ensures that the grain offering is accessible regardless of the offerer's cooking equipment. The common requirement across all methods: fine flour, oil, and unleavened.</p>",
        "6": "<p><strong>pittim pittim</strong>: 'into pieces, pieces' — intensive repetition indicating small, evenly broken fragments. <em>Pit</em> (H6595): a morsel/fragment. The griddle-baked grain offering is broken into pieces and oil poured over them before being brought to the priest. The breaking and oiling is a preparatory act by the offerer before the priests handle it. The repeated breaking (intensive plural) suggests thoroughness: not roughly torn but properly portioned.</p>",
        "7": "<p><strong>marcheshet</strong> (H4802): 'deep pan' or 'frying pan/cauldron' — a deeper vessel producing a thicker, richer product than the griddle. Only three mentions in the OT (all in Leviticus: 2:7; 7:9; 1 Chr 23:29 variant). The deep-pan grain offering is made with fine flour and oil like the others. The diversity of cooking vessels accommodates the range of domestic food preparation in ancient Israel while maintaining consistent sacrificial requirements.</p>",
        "8": "<p><strong>hiqriva</strong> (from <em>qarav</em>): 'to present/bring near' — the same root as <em>qorban</em> (v. 1:2). The grain offering is 'brought near' to the priest who then carries it to the altar. The repeated use of <em>qarav</em> vocabulary throughout Leviticus consistently frames sacrifice as approach, not payment: the worshiper draws near to God through the medium of the offering.</p>",
        "9": "<p>The priest takes the <strong>'azkara</strong> portion from the grain offering and burns it on the altar — <em>reah nihoah la-YHWH</em> (pleasing aroma to YHWH). The memorial-portion logic applies to all forms of the <em>minchah</em> regardless of preparation method: a representative portion goes up in smoke, and the rest goes to the priests. The <em>'azkara</em> is always wholly burned; it is the part that enacts the full transaction before YHWH.</p>",
        "10": "<p>The remainder (<em>ha-noteret</em>) of the grain offering belongs to Aaron and his sons — again classified as <em>qodesh qodashim</em> (most holy), echoing v. 3. The double classification (vv. 3 and 10) bookends the section on preparation variants, establishing that regardless of cooking method, the priestly remainder carries the same high holiness grade and the same consumption requirements.</p>",
        "11": "<p><strong>chametz</strong> (H2557): 'leaven, leavened bread' — from a root meaning 'to ferment.' <strong>Devash</strong> (H1706): 'honey' (or fruit syrup/date-honey). Both leaven and honey are forbidden from any grain offering brought as a fire offering (<em>isheh</em>) to YHWH. The reasons are not stated explicitly; the probable theological intuition is that fermentation and sweetening represent processes of transformation and corruption that are inappropriate for what is presented as pure tribute. In Israel's broader religious world, leaven and honey were used in Canaanite sacrificial contexts, which may inform their exclusion from Israelite altar practice.</p>",
        "12": "<p><strong>bikkurim</strong> (H1061): 'firstfruits' — from <em>bakhar</em> (to be early, to be first). The first produce of the harvest can be brought to YHWH as an offering (<em>qorban</em>), but the firstfruits are not to be offered on the altar as a <em>reah nihoah</em>. This differentiates the grain-offering system (which can generate <em>reah nihoah</em> via the <em>'azkara</em>) from the firstfruits offering, which is presented but not burned as incense. Lev 23:9-14 will specify the firstfruits wave-offering in detail.</p>",
        "13": "<p><strong>melach ha-berit Elohekha</strong> (<em>melach</em>, H4417): 'the salt of the covenant of your God.' Salt is a required addition to every grain offering: 'do not omit the salt of the covenant.' Salt preserves and prevents corruption; in ancient Near Eastern contexts, salt-covenant language denotes the permanence and trustworthiness of a treaty or agreement. <em>Berit melach</em> ('covenant of salt') appears also in Num 18:19 (the priestly covenant) and 2 Chr 13:5 (the Davidic covenant) — a perpetual, incorruptible commitment. Every grain offering seasoned with salt is a small enactment of the covenant's permanent character.</p>",
        "14": "<p><strong>'omer geresh</strong> (<em>geresh</em>, H1643): 'crushed/beaten grain.' <strong>Aviv</strong> (H24): 'fresh/young grain ears' — in early spring, before full ripening. The firstfruits grain offering uses <em>aviv</em> (the name of the first month, <em>Chodesh ha-Aviv</em>, is derived from this term). The grain is roasted (<em>qalui ba-esh</em>) and then beaten into crushed pieces before being brought. The firstfruits offering thus uses grain at its earliest stage — the beginning of the harvest — as representative of the whole yield to come.</p>",
        "15": "<p><strong>venatata aleiha shemen vesamt aleiha levonah</strong>: oil poured on and frankincense placed on the firstfruits grain offering — making it a proper <em>minchah</em> in form. The combination of crushed grain, oil, and frankincense is the standard <em>minchah</em> triad (as in v. 1). The firstfruits offering, despite its distinct occasion (harvest-beginning), uses the same sacred vocabulary of materials as the regular <em>minchah</em>.</p>",
        "16": "<p>The priest burns the <strong>'azkara</strong> (memorial portion) — some of the <em>geresh</em> (crushed grain) with some of the oil and all the frankincense — as a <em>reah nihoah la-YHWH</em>. The <em>'azkara</em> pattern closes the grain-offering chapter as it opened it (v. 2): whatever the variety, form, or occasion of the <em>minchah</em>, the memorial-portion logic applies. A part, properly burned, makes the whole acceptable.</p>"
    },
    "3": {
        "1": "<p><strong>zevach shelamim</strong> (H2077+H8002): 'fellowship offering' (also rendered 'peace offering,' 'well-being offering'). <em>Shelem</em> derives from <em>shalom</em> (wholeness, completeness, peace) or from <em>shalem</em> (to complete, to repay, to be at peace). The <em>shelamim</em> is the only offering from which the offerer also eats — after YHWH's portion (the fat burned on the altar) and the priestly portion, the offerer and family share a communal meal. It is a meal of reconciled community between the worshiper, the priests, and YHWH. <strong>Tamim</strong> (H8549): without defect — applies to both male and female animals in the <em>shelamim</em>, unlike the <em>'olah</em> which required male only.</p>",
        "2": "<p><strong>vesomach yado al rosh qorbano</strong>: laying of the hand on the offering's head — the <em>semikhah</em> gesture (covered in depth at 1:4). <strong>Shachat</strong>: slaughter. <strong>Zaraq</strong> dam: throw/toss blood. The same three acts (hand-laying, slaughter, blood-sprinkling) that characterize the <em>'olah</em> initiate the <em>shelamim</em> as well. The shared ritual structure across offering types signals that they participate in the same fundamental logic of substitution and approach, even as the disposition of the animal differs.</p>",
        "3": "<p><strong>chelev</strong> (H2459): 'fat' — specifically the superior, internal fat covering the organs (as distinct from the ordinary fat of muscle). The <em>chelev</em> belongs exclusively to YHWH: 3:16 will state <em>kol chelev la-YHWH</em> ('all fat is for YHWH'), and 3:17 forbids any Israelite from eating it. The best fat as YHWH's portion communicates that the highest and richest part of the animal belongs to the giver of all life. The same logic governs firstfruits (agricultural best to YHWH) and firstborn (progeny-best to YHWH).</p>",
        "4": "<p><strong>kelayot</strong> (H3629): 'kidneys' — in Hebrew thought the kidneys (like the heart) are associated with the moral and emotional interior of a person (<em>kelayot va-lev</em> = 'kidneys and heart' = the deepest self, e.g. Ps 16:7; 73:21; Jer 11:20). Offering the kidneys to YHWH symbolizes offering the hidden interior. <strong>Yoteret al ha-kaved</strong>: the fatty lobe or appendage of the liver. The liver was associated in ANE divination with revealing divine will (<em>haruspicy</em>). Offering this organ to YHWH implicitly rejects human divination: the 'divine indicator' is burned up as YHWH's portion, not inspected by humans.</p>",
        "5": "<p><strong>al ha-'olah</strong>: burned 'on top of the burnt offering' on the altar. The <em>shelamim</em>'s fat portions are added to the already-burning <em>'olah</em>, not offered separately. The layering of offerings on the altar is a feature of temple worship: the perpetual <em>'olah</em> (the <em>tamid</em>) serves as the fire-base on which all other offerings are placed. The cumulative burning speaks to the multi-dimensional nature of Israel's relationship with YHWH: dedication (<em>'olah</em>), tribute (<em>minchah</em>), and fellowship (<em>shelamim</em>) all ascending together.</p>",
        "6": "<p><em>Zevach shelamim la-YHWH min ha-tzon</em> — from the flock. The <em>shelamim</em> allows both male and female animals; this chapter covers cattle (vv. 1-5), sheep (vv. 6-11), and goats (vv. 12-16). The variety of acceptable animals for the fellowship offering reflects its communal and celebratory character — it is not restricted to the most costly animal. The shared meal it enables is available at different economic levels.</p>",
        "7": "<p><em>Kesev</em> (H3775): 'lamb' (specifically a male sheep). Presented before YHWH at the altar entrance. The lamb presentation begins the sheep variant of the fellowship offering. The gesture of presenting (<em>hiqriv</em>, from <em>qarav</em>) before YHWH at the tent entrance is the same approach-vocabulary used throughout: every sacrifice begins with drawing near.</p>",
        "8": "<p><strong>Semicha</strong> (laying of hands), slaughter, and blood-tossing are repeated identically for sheep — confirming the structural consistency of the <em>shelamim</em> ritual across animal types. The blood against the altar (<em>al ha-mizbeach saviv</em>) is the same zaraq-gesture as the <em>'olah</em>. The blood-application at the altar base is the act that formally completes the transfer: the animal's life, represented in its blood, is given to YHWH at the altar.</p>",
        "9": "<p><strong>'alyah</strong> (H451): the 'fat tail' — a term specific to the fat-tailed sheep breeds (<em>dumba</em>) common in the ancient Near East, which carry a large deposit of fat in the tail. The fat tail is specified for removal along with the <em>chelev</em> in sheep offerings; it belongs to YHWH's portion just as the internal fat does. The specification of a breed-specific anatomical feature shows the precision of the ritual system — it accounts for the biological realities of the available sacrificial animals.</p>",
        "10": "<p>The kidneys and liver lobe are described identically for sheep as for cattle (v. 4), using the same Hebrew terms. This verbatim repetition across animal categories (<em>kelayot veha-yoteret al ha-kaved</em>) reinforces that the theological significance is in the organs themselves — interior, hidden, decision-making organs — rather than in which animal they come from. The consistency of organ-theology across species is deliberate.</p>",
        "11": "<p><strong>lechem isheh la-YHWH</strong> (<em>lechem</em>, H3899 + <em>isheh</em>, H801): 'food of a fire offering to YHWH.' <em>Isheh</em> is a technical term for what is offered in fire; <em>lechem</em> (bread/food) applied to sacrifice describes what the altar-fire 'feeds' YHWH with — a bold anthropomorphic idiom. The LXX renders it with <em>karpoma</em> (fruit-offering) to avoid the anthropomorphism. The Hebrew text is unashamed to use food language for YHWH's reception of the sacrifice: the covenant God is the host of a meal at which both he and his people eat.</p>",
        "12": "<p><em>'Ez</em> (H5795): goat (female goat or the species generally). The goat variant of the <em>shelamim</em> is presented with the same formula as the sheep (vv. 7-11). The standardized formula for all three animal variants (cattle, sheep, goat) communicates that the <em>shelamim</em> is a genuinely accessible offering: cattle for the wealthy, sheep for the middle, goats for those with less. The fellowship-meal it enables is not socioeconomically restricted.</p>",
        "13": "<p>The goat's <em>semicha</em>, slaughter, and blood-tossing are identical to the prior animal variants. The ritual-formula repetition is characteristic of Leviticus's literary style: the repetition is not editorial redundancy but liturgical specification. The reader (and the officiating priest) must perform each act for each animal exactly as specified; the verbal repetition encodes the requirement that no shortcut is acceptable.</p>",
        "14": "<p>The fat covering the entrails (<em>chelev ha-mekaseh et ha-qerev</em>) is specified for the goat offering identically to cattle (v. 3). <em>Chelev</em> is the technically classified 'best fat' — the subcategory of internal organ fat that belongs exclusively to YHWH (v. 16). The exact specification of which fat (not all fat, but the classified <em>chelev</em>) prevents confusion between the dietary law and the offering requirement.</p>",
        "15": "<p>The kidneys and liver lobe again — identical in all three animal categories. The threefold repetition of these specific organ designations (vv. 4, 10, 15) establishes them as the fixed 'interior theology' of the <em>shelamim</em>: whatever the animal, the inner most-significant organs go to YHWH. The offerer eats the rest; the priest receives the breast and thigh (Lev 7:28-34); YHWH receives the fat, blood, kidneys, and liver-lobe.</p>",
        "16": "<p><strong>Kol chelev la-YHWH</strong>: 'all the fat belongs to YHWH.' This concluding declaration for the <em>shelamim</em> chapters is a categorical claim: the best fat of any animal, in any offering context, is YHWH's portion. <em>Reah nihoah</em> closes the offering formula. The <em>chelev</em>-reservation is paired with blood-reservation in v. 17: the two elements most associated with life and fertility in ANE food and religious culture are both entirely YHWH's — they may not be consumed by humans in any context.</p>",
        "17": "<p><strong>Chuqat 'olam ledoroteichem</strong> (<em>chuqat 'olam</em>, H2708+H5769): 'a perpetual ordinance throughout your generations' — the strongest legal formula in Leviticus, indicating a non-negotiable, permanent prohibition. <strong>Chelev</strong> and <strong>dam</strong> (blood) may not be eaten wherever you dwell. The double prohibition (no fat, no blood) applies outside the sacrificial context as well — in any food. The life-blood principle (Lev 17:11) and the best-portion principle (fat to YHWH) together define the outer boundaries of Israelite food ethics: what is most life-containing belongs exclusively to the life-giver.</p>"
    },
    "4": {
        "1": "<p>The divine-speech formula <em>vayedabber YHWH el-Moshe lemor</em> (the LORD spoke to Moses, saying) introduces the fourth major offering type. This formulaic opener distinguishes the <em>chattat</em> from the offerings in chs. 1-3: the purification offering is presented as a separate divine command, not a continuation of the previous instructions. The break marks the conceptual distinction between tribute/fellowship offerings (chs. 1-3) and the purgation offering for sin (ch. 4).</p>",
        "2": "<p><strong>bishgagah</strong> (H7684): 'unintentionally, through inadvertence' — from <em>shagag</em> (to go astray, to err). The <em>chattat</em> (purification offering) covers only sins committed <em>bishgagah</em>, not intentional high-handed transgressions (<em>beyad ramah</em>, Num 15:30-31, for which no sacrifice is available — only divine mercy or death). The distinction between inadvertent and deliberate sin is fundamental to the sacrificial system's scope. The <em>chattat</em> is for what was done without full moral intent; it does not mechanically erase premeditated rebellion.</p>",
        "3": "<p><strong>ha-kohen ha-mashiach</strong> (<em>mashiach</em>, H4899): 'the anointed priest' — the high priest. The same root as <em>meshiach</em> (Messiah/Christ = the anointed one). The anointed priest's unintentional sin is treated with the gravest category of sin-offering (a bull, the most expensive animal) because his sin carries communal consequences: <em>le'ashmat ha-'am</em> — 'bringing guilt on the people.' The leader's moral failure implicates the entire community he represents. This principle of representative contamination applies at every social level in ch. 4 (priest, community, leader, individual).</p>",
        "4": "<p><strong>Semicha</strong> on the bull's head before the tent of meeting — the same identification gesture as in the <em>'olah</em> (1:4) and <em>shelamim</em> (3:2,8,13). The laying of hands on the <em>chattat</em> bull formally identifies the offerer with the sacrifice, transferring his sin to the animal. The physical contact transfers not just identity but guilt (<em>'avon</em>) — the animal becomes his representative before YHWH as a guilt-bearer.</p>",
        "5": "<p><strong>El ohel mo'ed</strong>: the blood of the high priest's <em>chattat</em> is brought <em>inside</em> the tent of meeting — a feature unique to this category of offering. The blood-application at the incense altar inside the tent (v. 7) is the most sacred blood ritual in the regular calendar. The spatial escalation (courtyard altar vs. inner sanctuary) reflects the severity of the sin being addressed: the higher the rank of the sinner, the deeper into the sanctuary the atonement must reach.</p>",
        "6": "<p><strong>Vehizel ha-kohen et etzba'o min ha-dam</strong>: 'The priest dips his finger in the blood.' <strong>Sheva pe'amim</strong>: 'seven times' — the seven-fold sprinkling before the <em>parochet</em> (the sanctuary veil). The number seven is the covenant-completion number throughout the OT (seven-day week, seven-year sabbatical, seven-fold sprinkling). The sprinkling before the veil directs the blood toward the Most Holy Place without entering it — the atonement-effect reaches the holiest space through blood-application at its threshold.</p>",
        "7": "<p><strong>Qarnot ha-mizbeach</strong> (<em>qeren</em>, H7161): 'horns of the altar' — the four projections at the corners of the incense altar. Blood applied to the altar's horns (repeated across multiple offering types) is the most graphic form of blood-application: the horns are the altar's most prominent points, where the power of the sacrifice is concentrated. The pouring of the remainder at the base (<em>el yesod mizbeach ha-'olah</em>) disposes of the blood with reference to the burnt-offering altar — the two altars are connected in the purification ritual.</p>",
        "8": "<p><strong>Chelev</strong> portions specified for the <em>chattat</em> bull — identical to the <em>shelamim</em> (vv. 8-10 repeat 3:3-5 verbatim). The fat-burning on the altar of burnt offering applies across all offering types where an animal is offered: the best fat always goes to YHWH regardless of the offering's purpose. The fat-theology (v. 3:16 <em>kol chelev la-YHWH</em>) is not suspended for the sin offering; purification and tribute both require giving the best.</p>",
        "9": "<p><strong>Kelayot</strong> (kidneys) and liver lobe specified identically to the <em>shelamim</em> — the interior organs belong to YHWH even in the purgation offering. The theological claim is consistent: even when the offering is about removing sin rather than celebrating fellowship, the hidden, interior-self organs are YHWH's portion. What is most inward is most holy and most fully YHWH's.</p>",
        "10": "<p>'Just as they are removed from the ox of the <em>shelamim</em>' — the explicit cross-reference to 3:3-5. The identical fat-portion instructions for the <em>chattat</em> and the <em>shelamim</em> signal that the altar's receiving of YHWH's portion is a constant across offering types. The ritual logic is portable: what belongs to YHWH from the fellowship offering belongs to him from the purification offering as well. The divine portion is not renegotiable based on the offering's purpose.</p>",
        "11": "<p><strong>'Or ha-par</strong> (the bull's hide) + <strong>kol bisaro</strong> (all its flesh) — head, legs, entrails, and dung — the entire animal minus the fat portions burned on the altar. The priests receive no portion from the high priest's or the community's <em>chattat</em> bull (unlike individual sin-offerings in 6:26 where the priest eats). The complete disposal of the carcass outside the camp marks the severity of these communal or priestly sin offerings: no benefit returns to any human party.</p>",
        "12": "<p><strong>El-mikhon ma'aneh ha-deshen</strong>: to the 'clean place' outside the camp where the ashes are disposed of. The entire bull — hide, flesh, head, legs, entrails, dung — is carried outside and burned on wood. The burning-outside-the-camp is the complete removal of the sin-material from the covenant community. Its exclusion from the priestly food-system and the camp itself visualizes what atonement accomplishes: the sin-bearing material is expelled and destroyed.</p>",
        "13": "<p><strong>Kat ha-'edah kullah</strong> ('the entire community') sinning <em>bishgagah</em> — when the corporate body commits an unintentional violation. The extension of the offering system to cover the community as a collective (not just individuals) shows that Israel is conceived as a covenanted corporate entity before YHWH: the community can sin as a body, and the community must make atonement as a body. <em>Venelam davar min ha-'edah</em> — 'the matter was hidden from the assembly' — unintentional community sin by definition involves obscured moral perception.</p>",
        "14": "<p>When the communal sin becomes known (<em>nodat hachata't</em>), the assembly brings a <em>par ben baqar</em> (young bull from the herd) — the same animal as the high priest's offering (v. 3). The matched animal for priest and community confirms that the community bears collective guilt equivalent to that of its highest leader. The size of the required offering scales with the scope of the sinner's representative authority.</p>",
        "15": "<p><strong>Ziqne ha-'edah</strong> (<em>zaqen</em>, H2205): 'the elders of the community.' The elders lay hands on the bull's head <em>on behalf of the assembly</em> — they are the community's representatives in the semicha act. The representative structure of Israel's government (elders representing the people) is formally incorporated into the atonement mechanism: the elders' hands = the community's hands. Corporate guilt is addressed through representative action at every level.</p>",
        "16": "<p>The anointed priest (<em>ha-kohen ha-mashiach</em>) takes the blood inside the tent of meeting — the same procedure as for his own <em>chattat</em> (v. 5). The community's sin, like the priest's, requires the blood to reach the inner sanctuary. The spatial reach of the blood-application is determined by the gravity and representational scope of the sin: the more comprehensive the sin, the deeper into the sanctuary the blood must go.</p>",
        "17": "<p>Seven-fold sprinkling (<em>sheva pe'amim</em>) before the veil — identical to the procedure for the priest's own offering (v. 6). The communal sin offering uses the identical blood-manipulation technique as the priestly offering. The seven-fold sprinkling before the parochet is the maximum blood-application ritual in the regular calendar (only Yom Kippur adds entry into the Most Holy Place itself).</p>",
        "18": "<p><strong>Qarnot ha-mizbeach</strong> (horns of the altar) — the incense altar inside the tent. Blood on the horns + remainder poured at the base of the burnt-offering altar (v. 18). The double altar ritual (incense altar inside + burnt offering altar outside) links the two spaces of the tabernacle: the purification reaches both the inner court (where YHWH dwells) and the outer court (where sacrifice is performed). Atonement works from the inside out and from the outside in simultaneously.</p>",
        "19": "<p><strong>Ve'et kol chelvo yarim mimenu</strong>: 'All its fat he removes.' The fat-burning on the altar — consistent across all offering types. Even in the community's sin offering, where the entire carcass is burned outside the camp (no priestly food-share), the fat portions are first properly burned on the altar. The two disposals happen in order: first the fat to the altar (YHWH's portion); then the remainder to outside the camp (the removal of sin).</p>",
        "20": "<p><strong>Vekipper aleihem ha-kohen venislach lahem</strong>: 'The priest makes atonement for them, and they will be forgiven.' <em>Kipper</em> (H3722): to make atonement, to cover, to ransom. <em>Salach</em> (H5545): to forgive, to pardon — exclusively used of YHWH's forgiveness of humans in the OT (never of human-to-human forgiveness). The pairing is the standard outcome formula for the <em>chattat</em>: atonement performed by the priest + forgiveness granted by YHWH. The two acts are distinct and sequential: ritual action enables divine response.</p>",
        "21": "<p><strong>Chattat ha-qahal</strong>: 'the sin offering of the community.' Burned entirely outside the camp, as with the high priest's <em>chattat</em> (v. 12). The outside-the-camp burning marks these two categories (priestly and communal) as the 'whole-consumption' <em>chattat</em>: no one eats any part. The Epistle to the Hebrews (13:11-13) draws on this: 'the bodies of those animals whose blood is brought into the holy places by the high priest as a sin offering are burned outside the camp' — and then applies it to Jesus, who suffered 'outside the gate.'</p>",
        "22": "<p><strong>Nasi</strong> (H5387): 'leader, prince, chief' — the community's civil head (as distinct from the <em>kohen ha-mashiach</em>, the religious head). The term <em>nasi</em> in Ezekiel becomes a key eschatological title for the ideal future leader (Ezek 34:24; 37:25). The <em>nasi</em>'s sin offering uses a male goat (<em>se'ir 'izzim</em>, v. 23) rather than a bull — a scaled-down offering reflecting his lesser representative scope compared to the priest or the community as a whole.</p>",
        "23": "<p><strong>Se'ir 'izzim</strong> (H8163+H5795): 'male goat.' The leader's <em>chattat</em> animal is a male goat — identical to one of the two Yom Kippur goats (Lev 16:9) and the offering for national sin on appointed festivals (Num 28-29). The male goat becomes the standard <em>chattat</em> animal for leaders and communities on regular observances. The gradation of sin-offering animals (bull for priest/community; male goat for leader; female goat or lamb for commoner) reflects the graduated-responsibility principle: higher authority = larger animal = more severe accounting.</p>",
        "24": "<p>The leader lays hands on the goat and slaughters it <em>bimqom asher yishchat et ha-'olah lifne YHWH</em> — in the place where the burnt offering is slaughtered. The <em>chattat</em> animal for the leader is killed in the same location as the <em>'olah</em> (north side of the altar, cf. 1:11; 6:25), not in a separate ritual space. The shared slaughter-location across offering types means the ritual geography of the tabernacle courtyard is a fixed, non-negotiable spatial order.</p>",
        "25": "<p>Blood on the <strong>qarnot mizbeach ha-'olah</strong> (horns of the burnt offering altar) — not the incense altar as in the priestly and communal <em>chattat</em>. The leader's sin offering applies blood to the outer burnt-offering altar, not the inner incense altar. The difference marks the lesser gravity: the leader's sin does not require blood to reach the inner sanctuary. The spatial mapping of sin-severity is precise: the deeper the sanctuary penetration, the graver the sin being addressed.</p>",
        "26": "<p><strong>Kipper</strong> + <strong>nislach lo</strong> (atonement made + forgiveness granted) — the standard outcome formula for the <em>chattat</em>. The <em>nislach lo</em> ('forgiven to him') is the divine grant of pardon that follows the human ritual of atonement. Throughout Leviticus, forgiveness is never automatic or mechanical: it requires the appropriate ritual action (<em>kipper</em>) but its ultimate granting is YHWH's sovereign act of <em>selach</em>. The two moments (human ritual + divine pardon) are inseparable but distinguishable.</p>",
        "27": "<p><strong>Am ha-'aretz</strong> (<em>am</em>, H5971 + <em>'aretz</em>, H776): 'a person of the land' — an ordinary member of the Israelite community, as distinct from the priest, the community leadership, or the <em>nasi</em>. The term later takes on various social/religious connotations in the Second Temple period, but in Leviticus it simply means any ordinary individual Israelite who is not in a leadership role. The offering for the individual commoner is a female animal (goat or lamb) rather than a male, reflecting the smaller scale of individual vs. representative sin.</p>",
        "28": "<p><strong>Se'irat 'izzim</strong> (H5795+H8163): female goat — the individual's <em>chattat</em> animal for an intentional-class violation. The female animal for the individual's sin offering reflects the gradation principle throughout ch. 4: bull (anointed priest / community) → male goat (leader) → female goat or female lamb (individual). The systematic gradation is not about the animal's monetary value per se but about the representative scope: those who represent more offer more. The individual offers a female animal because they represent only themselves.</p>",
        "29": "<p>Semicha, slaughter, and blood at the burnt-offering altar — the same spatial and gestural sequence for the individual's <em>chattat</em> as for the leader's (v. 24-25). The ritual actions are identical across all categories; what differs is the blood-application location (inner vs. outer altar) and the animal used. The structural consistency of the ritual ensures that every level of Israelite society participates in the same system of covenant restoration.</p>",
        "30": "<p>Blood on the horns of the burnt-offering altar (<em>mizbeach ha-'olah</em>) with the remainder poured at the base — the same as the leader's offering (v. 25). The individual Israelite's blood ritual matches the leader's in location, confirming that both outer-altar offerings share the same spatial category (as distinguished from the inner-altar offerings of the priest and community). The taxonomy is precise and consistent.</p>",
        "31": "<p><strong>Reah nihoah la-YHWH</strong> — the pleasing-aroma formula appears for the first time in the <em>chattat</em> chapter at the individual's offering. The earlier <em>chattat</em> variants (priest, community, leader) do not use this formula; the individual's offering does. This may reflect that the fat-burning of the individual's <em>chattat</em> is treated more like the <em>shelamim</em> fat-burning (which feeds the priestly family rather than being entirely consumed). The <em>kipper</em> + <em>nislach lo</em> outcome formula closes the individual female-goat offering.</p>",
        "32": "<p><strong>Kivsa</strong> (H3775 female): 'a ewe-lamb' — the alternative animal for the individual's <em>chattat</em>. The option of either a female goat or a ewe-lamb provides economic flexibility within the individual-offering category. Both animals are female and must be <em>temimah</em> (without defect). The two-animal option (goat or lamb) for the commoner's sin offering means that the individual's access to the atonement system is the most flexible in the entire ch. 4 gradation.</p>",
        "33": "<p>The ewe-lamb's <em>chattat</em> ritual is performed <em>linetach ha-'olah</em> — beside the burnt-offering location. The spatial marker repeated from v. 29 and v. 24 confirms the fixed geography: the leader's and individual's sin offerings are both performed at or near the burnt-offering location (north side of the outer altar), not in front of the veil. The spatial distinction separates the priestly/communal category from the leader/individual category throughout ch. 4.</p>",
        "34": "<p>Blood applied to the <strong>qarnot mizbeach ha-'olah</strong> — identical to the female-goat procedure (v. 30). The lamb and goat procedures for the individual <em>chattat</em> are structurally identical: same animal-sex category, same spatial location, same blood application point. The two animal options differ only in species; the ritual procedure is the same. The systematic parallelism throughout ch. 4 creates a graduated but unified system: one ritual logic, five implementation levels (priest, community, leader, individual-goat, individual-lamb).</p>",
        "35": "<p><strong>Kipper alav ha-kohen al chata'to asher chata venislach lo</strong>: 'The priest makes atonement for the sin he committed, and he will be forgiven.' The chapter closes with the same outcome formula that appears at each stage (vv. 20, 26, 31) — <em>kipper</em> + <em>nislach</em>. The repetition of this paired formula across all four social categories (priest, community, leader, individual) is programmatic: the entire <em>chattat</em> system exists to make this outcome available to everyone in Israel, from the highest priest to the lowest commoner, through properly executed ritual atonement and YHWH's sovereign grant of pardon.</p>"
    }
}

def main():
    data = load_comm('mkt-original', 'leviticus')
    merge_comm(data, LEVITICUS)
    save_comm('mkt-original', 'leviticus', data)

    import json as _json, pathlib as _p
    ROOT2 = _p.Path(__file__).parent.parent
    out = _json.loads((ROOT2 / 'data/commentary/mkt-original/leviticus.json').read_text())
    il  = _json.loads((ROOT2 / 'data/interlinear/leviticus.json').read_text())
    all_ok = True
    for ch in range(1, 5):
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(out.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
